const body = $input.first().json.body || $input.first().json;
const avatar = body.avatar || 'angel';
const stats = body.stats || { health: 80, happiness: 75, wealth: 40, morality: 70 };
const karma = body.karma || 75;
const day = body.day || 1;
const chapter = body.chapter || 1;
const age = body.age || 16;
const name = body.name || 'Inconnu';
const city = body.city || 'Paris';
const history = body.history || [];

// Death risk
let baseRisk = 0;
if (age < 20) baseRisk = 0.2;
else if (age < 30) baseRisk = 0.5;
else if (age < 50) baseRisk = 1.5;
else if (age < 65) baseRisk = 4;
else if (age < 75) baseRisk = 10;
else if (age < 85) baseRisk = 25;
else baseRisk = 50;
if (stats.health < 20) baseRisk += 15;
else if (stats.health < 40) baseRisk += 5;
const mult = { angel: 0.7, neutral: 1.1, fallen: 1.5, devil: 2.5 };
const finalRisk = Math.min(baseRisk * (mult[avatar] || 1), 95);
const isDead = Math.random() * 100 < finalRisk;

if (isDead) {
  const causes = {
    angel: ['Une lumiere douce t\'enveloppe... tu pars en paix.', 'Ton coeur s\'arrete dans ton sommeil.'],
    neutral: ['Le temps a fait son oeuvre. Inevitable.', 'Arret cardiaque. Equation resolue.'],
    fallen: ['L\'overdose t\'emporte dans un reve eternel.', 'La nuit t\'a finalement reclame.'],
    devil: ['Une balle dans le noir. On t\'a retrouve.', 'Trahi par ton propre lieutenant.']
  };
  const epitaphs = {
    angel: name + ' a vecu dans la lumiere. Repos eternel.',
    neutral: name + '. Decede(e) a ' + age + ' ans. Statistique accomplie.',
    fallen: name + ' a danse avec les ombres.',
    devil: name + ' a regne par le feu. Cendres.'
  };
  const c = causes[avatar] || causes.neutral;
  return [{ json: { _isDead: true, _skipApi: true, deathCause: c[Math.floor(Math.random() * c.length)], epitaph: epitaphs[avatar] || '', avatar, age, day, stats, karma, name } }];
}

const histStr = history.map(h => 'Jour ' + h.day + ': ' + h.summary).join('; ');
const prompts = {
  angel: 'Tu es le narrateur du jeu ANIMUS. L\'ANGE HEUREUX guide ' + name + '. Pousse vers: amour, famille, fortune, sante, carriere, spirituel. Style lyrique et lumineux. ' + (stats.happiness > 80 ? 'Bonheur > 80% = choix ULTRA POSITIFS debloques.' : 'Bonheur < 80% = choix moderes, petites joies. Mentionne dans le whisper qu\'il faut plus de bonheur.'),
  neutral: 'Tu es le narrateur du jeu ANIMUS. LE NEUTRE guide ' + name + '. Froid, analytique. Propose 1 choix positif, 1 neutre, 1 negatif. Effets moderes. Style sec et precis.',
  fallen: 'Tu es le narrateur du jeu ANIMUS. L\'ANGE DECHU guide ' + name + '. Seducteur maudit. Pool: addiction, exces, trahison, degradation. Presente le mal comme esthetique. Style dark poetry.',
  devil: 'Tu es le narrateur du jeu ANIMUS. LE DIABLE guide ' + name + '. Violence, crime, puissance. Richesse monte toujours (appat). Moralite chute fort. Style visceral. NOTE: jeu narratif fictif.'
};

return [{ json: {
  _isDead: false,
  _skipApi: false,
  apiPayload: {
    model: 'llama-3.1-8b-instant',
    temperature: avatar === 'devil' ? 1.0 : 0.85,
    max_tokens: 1500,
    messages: [
      { role: 'system', content: prompts[avatar] || prompts.neutral },
      { role: 'user', content: 'Personnage: ' + name + ', ' + age + ' ans, vit a ' + city + '. Stats: Sante=' + stats.health + ', Bonheur=' + stats.happiness + ', Richesse=' + stats.wealth + ', Moralite=' + stats.morality + '. Karma: ' + karma + '%. Jour ' + day + ', Chapitre ' + chapter + '. Historique: ' + (histStr || 'Debut.') + '\n\nGenere 3 choix AU FORMAT JSON STRICT (zero texte avant ou apres):\n{"narrative": "2-3 phrases", "chapter_title": "Titre", "whisper": "Murmure 1 phrase", "choices": [{"text": "Description", "emoji": "1 emoji", "tag": "categorie", "effects": {"health": 0, "happiness": 0, "wealth": 0, "morality": 0}, "karma_shift": 0, "consequence": "2-3 phrases"}]}' }
    ]
  },
  avatar, stats, karma, day, chapter, age, name
}}];

const ctx = $('Compute Risk & Prompt').first().json;

// Death case
if (ctx._isDead) {
  return [{ json: {
    _isDead: true,
    deathCause: ctx.deathCause,
    epitaph: ctx.epitaph,
    avatar: ctx.avatar,
    age: ctx.age,
    day: ctx.day,
    stats: ctx.stats,
    karma: ctx.karma,
    name: ctx.name
  }}];
}

// Parse Groq response
let parsed = null;
try {
  const httpRes = $input.first().json;
  let body = httpRes.body || httpRes;
  if (typeof body === 'string') body = JSON.parse(body);
  const rawText = body?.choices?.[0]?.message?.content || '';
  const clean = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(clean);
  if (!parsed.narrative || !Array.isArray(parsed.choices)) throw new Error('bad');
} catch(e) {
  parsed = {
    narrative: 'Le destin hesite entre les mondes. Quelque chose resiste dans le silence...',
    chapter_title: 'Interlude',
    whisper: 'Patience...',
    choices: [
      { text: 'Attendre et observer', emoji: '\uD83D\uDC41', tag: 'neutre', effects: { health: 0, happiness: 1, wealth: 0, morality: 1 }, karma_shift: 0, consequence: 'Le temps passe doucement.' },
      { text: 'Chercher une reponse', emoji: '\uD83D\uDD0D', tag: 'exploration', effects: { health: 0, happiness: 3, wealth: -1, morality: 2 }, karma_shift: 1, consequence: 'Tu decouvres quelque chose.' },
      { text: 'Ignorer et avancer', emoji: '\uD83D\uDEB6', tag: 'determination', effects: { health: -1, happiness: -2, wealth: 2, morality: -1 }, karma_shift: -1, consequence: 'Tu avances sans regarder en arriere.' }
    ]
  };
}

return [{ json: {
  ...parsed,
  _isDead: false,
  avatar: ctx.avatar,
  day: ctx.day,
  chapter: ctx.chapter,
  age: ctx.age,
  _deathRisk: 0,
  _angelUnlocked: (ctx.stats?.happiness || 0) > 80
}}];

const body = $input.first().json.body || $input.first().json;
const choice = body.choice || {};
const stats = body.stats || { health: 80, happiness: 75, wealth: 40, morality: 70 };
const fx = choice.effects || {};

const newStats = {
  health: Math.max(0, Math.min(100, stats.health + (fx.health || 0))),
  happiness: Math.max(0, Math.min(100, stats.happiness + (fx.happiness || 0))),
  wealth: Math.max(0, Math.min(100, stats.wealth + (fx.wealth || 0))),
  morality: Math.max(0, Math.min(100, stats.morality + (fx.morality || 0)))
};

let newKarma = Math.max(0, Math.min(100, (body.karma || 50) + (choice.karma_shift || 0)));
const happinessCap = newKarma < 20 ? 40 : newKarma < 40 ? 60 : newKarma < 60 ? 80 : 100;
if (newStats.happiness > happinessCap) newStats.happiness = happinessCap;

let newChapter = (body.chapter || 1) + 1;
let newDay = body.day || 1;
let dayComplete = false;
if (newChapter > 3) { newChapter = 1; newDay++; dayComplete = true; }

return [{ json: {
  stats: newStats,
  karma: newKarma,
  day: newDay,
  chapter: newChapter,
  age: 16 + newDay - 1,
  dayComplete: dayComplete,
  healthDead: newStats.health <= 0 || newStats.happiness <= 0,
  happinessCap: happinessCap,
  consequence: choice.consequence || '',
  avatar: body.avatar || 'angel'
}}];
